@Transactional
public Order createOrder(CreateOrder cmd) {
  Order o = orderRepo.save(Order.from(cmd));
  outboxRepo.save(new OutboxEvent(
    UUID.randomUUID(), "OrderCreated", o.id(), toJson(o), OutboxStatus.PENDING));
  return o;
}

